+#[test]
+fn reaping_last_field_deletes_the_whole_hash_key() {
+    let mut store = Store::new();
+    seed_hash(&mut store, b"h", &[(b"only", b"v")]);
+    store.hash_field_set_abs_expiry(
+        b"h",
+        b"only",
